-- +goose StatementBegin
INSERT INTO `model_scenario` (`type`, `name`, `summary`, `description`, `detail`, `category`, `sort_order`) VALUES

-- ========== 决策模型：经典框架 ==========
('model', '框架模型', '当问题模糊时，用决策→选项→标准→约束→截止日期来理清思路', '面对模糊、混乱的决策问题时，先不要急着选方案。用五步框架理清：到底要决定什么？有哪些选项？用什么标准判断？有什么约束条件？截止日期是什么？这能把焦虑转化为可操作的选择。', '适用场景：问题定义不清、选项混杂、情绪和事实混在一起时。典型场景：要不要换工作、选哪个offer、该不该结束一段关系。', '决策-经典框架', 1),
('model', '加权矩阵', '多个选项+明确标准时，给标准打权重，给选项打分，算总分比较', '当面对多个选项和多个评判标准时，列出所有标准并分配权重（总和100%），然后对每个选项在每个标准上打分（1-10），加权求和后比较总分。最后做敏感性检查：如果某个权重变化，结论是否改变？', '适用场景：选offer、选方案、选供应商、选学校等多标准多选项决策。避免：标准之间高度相关导致重复计分。', '决策-经典框架', 2),
('model', '10/10/10模型', '10分钟后、10个月后、10年后，这个决定会让你感觉如何？', '当情绪或短期压力过大时，用三个时间尺度审视决定：10分钟后你会怎么想？10个月后呢？10年后呢？大多数让人焦虑的决定，10个月后就不那么重要了；而真正重要的决定，10年后的影响才显现。', '适用场景：情绪化决策、冲动决策、害怕做出错误选择。典型场景：要不要表白、要不要辞职、要不要当面指出问题。', '决策-经典框架', 3),
('model', '后悔最小化', '想象80岁的自己回望此刻，哪个选择会让你更少后悔？', '站在未来的视角看现在的选择：如果我不做这件事，未来的我会后悔吗？如果我做了但失败了，我能接受吗？贝佐斯用这个方法决定离开华尔街创办亚马逊——他知道自己不会后悔尝试，但会后悔没有尝试。', '适用场景：职业转变、创业、学习新技能、结束或开始重要关系。关键：区分"遗憾"和"教训"——尝试后的失败是教训，不尝试的错过是遗憾。', '决策-经典框架', 4),
('model', 'WRAP模型', '拓宽选项→现实检验假设→保持距离→准备出错', '决策四大步骤：1）拓宽选项集，不要只在A/B之间选；2）用小实验检验关键假设，而不是纯靠想象；3）在做决定前先睡一觉，保持距离避免情绪干扰；4）提前想好如果错了怎么办。', '适用场景：重大决策、容易陷入二元选择时、存在确认偏误风险时。这是《决策力》(Decisive)的核心框架。', '决策-经典框架', 5),

-- ========== 决策模型：风险管理 ==========
('model', '事前验尸', '假设这个选择已经失败了，最可能的原因是什么？现在如何预防？', '在承诺一个高风险选项之前，先做"事前验尸"：想象三个月后这个选择彻底失败了，写下最可能的3-5个失败原因。然后为每个原因设置预警信号和预防措施。这能把乐观偏见转化为风险意识。', '适用场景：启动新项目、重大投资、创业、搬迁、重要谈判前。与"事后复盘"配对使用效果最佳。', '决策-风险管理', 6),
('model', '止损模型', '尝试选项→定义失败信号→设置退出规则', '开始一个选择时就定义：什么样的信号说明这条路走不通？具体到什么指标、什么时间点就该停止？把"止损线"写下来，避免在过程中不断加码、越陷越深。', '适用场景：投资、项目推进、关系经营、学习新技能——任何有"沉没成本陷阱"的场景。核心：止损线要在情绪平静时设定，不是在亏损时临时决定。', '决策-风险管理', 7),
('model', '沉没成本配额', '设定最大投入上限（时间/金钱/精力），到了就停，提取经验不报复性投入', '明确告诉自己"我最多再投入X"——可以是两周时间、1000元钱、每天2小时精力。到了上限还没有关键进展，就果断停止，把经验记下来。关键是"不报复性投入"——不要因为不甘心而继续加码。', '适用场景：任何感觉自己"已经投入太多所以不能放弃"的场景。典型：万元陷阱、不合适的工作、效果不好的项目。', '决策-风险管理', 8),
('model', '备用计划模型', '主要选择→失败情景→备用选项→切换触发条件', '为重要决策准备Plan B：如果主要选择失败，具体会是什么情景？我的备用选项是什么？什么信号出现时就切换？备用计划不是"到时候再说"，而是提前想好的切换方案。', '适用场景：需要勇气但不鲁莽的选择——创业、跳槽、大额投资、重要谈判。', '决策-风险管理', 9),
('model', '极小化极大模型', '最小化最可信的最坏下行风险', '当损失保护比上行收益更重要时，先问：最可信的最坏结果是什么？然后选择那个让最坏结果"最不坏"的选项。不是最小化所有可能的坏结果，而是最小化"真正可能发生"的坏结果。', '适用场景：健康决策、安全决策、财务底线保护、不可逆决策。与"最大化最小收益"互补。', '决策-风险管理', 10),

-- ========== 决策模型：分析工具 ==========
('model', '问题定义模型', '一句话定义问题→5W2H展开→5个为什么挖根因→识别隐藏假设和核心冲突', '在解决问题之前，先用一句话说清楚"现在到底需要解决什么"。然后用5W2H展开全貌，用5个为什么挖到根因，检查有哪些隐藏假设，识别核心冲突。大多数时候，准确定义问题比急于解决问题更重要。', '适用场景：问题模糊、情绪化、多个问题混杂、感觉"什么都是问题"时。', '决策-分析工具', 11),
('model', 'MECE逻辑树', '列出所有因素→分组使相互独立完全穷尽→消除重复和缺口', '把问题拆解成不重叠、不遗漏的类别。每个类别下的子项也要满足MECE。这能避免"一边想一边乱"，确保你考虑了所有方面，同时不重复分析。', '适用场景：复杂问题拆解、方案设计、报告框架、面试答题结构化。', '决策-分析工具', 12),
('model', '鱼骨图根本原因', '从人员、流程、资源、环境、规则、衡量六个维度找根本原因', '当问题反复出现时，不要只治标。从六个维度系统排查：是人的问题（能力/态度）？流程问题？资源不足？环境变化？规则不合理？衡量指标有误？找到真正的根因才能彻底解决。', '适用场景：反复出现的问题、质量事故、团队效率低、客户投诉等需要深挖根因的场景。', '决策-分析工具', 13),
('model', '第一性原理', '观察事实→去除假设→识别不可简化的真理→从基本原理重建方案', '不要被"行业惯例""大家都这么做"束缚。回到最基本的事实和原理，问"什么是确定为真的？"然后从零开始推导解决方案。马斯克用这个方法重新计算火箭成本，发现材料费只有市价的2%。', '适用场景：打破行业惯例、重新设计方案、创新、质疑"不可能"。', '决策-分析工具', 14),
('model', '贝叶斯更新', '先验信念→新证据→更新概率→调整决策', '不要非黑即白地判断。先有一个初始概率估计（先验），然后根据新证据不断更新。关键原则：证据越强，更新幅度越大；多个弱证据的组合也能大幅改变判断。', '适用场景：信息不完整时的判断、创业验证、关系评估、投资判断——任何需要"边做边调整"的场景。', '决策-分析工具', 15),

-- ========== 决策模型：行动策略 ==========
('model', '杠杆模型', '大部分资源保持安全，少量投入高上行收益的赌注', '不把所有鸡蛋放一个篮子，也不完全保守。80%资源放在稳定的基础（主业、核心技能），20%放在高风险高回报的探索（副业、新技能、人脉拓展）。这样既不裸辞，也不原地不动。', '适用场景：职业发展、投资配置、时间分配、技能培养。', '决策-行动策略', 16),
('model', '试点模型', '小型试验→测量结果→学习→决定扩大或停止', '不确定一件事是否可行？不要做完整规划再行动，而是用最小成本做个小试验。跑两周看数据，根据结果决定是扩大投入还是止损退出。这比无尽的分析更能减少不确定性。', '适用场景：新业务验证、习惯养成、技能学习、关系试探——任何"不确定但想尝试"的场景。', '决策-行动策略', 17),
('model', '如果-那么计划', '如果信号X出现，那么我就做Y', '把不确定的决策转化为适应性计划。提前定义触发条件和对应行动，这样当情况变化时不用临时思考，直接执行预设方案。研究表明这比"我要努力做X"有效2-3倍。', '适用场景：习惯养成、风险应对、谈判策略、项目管理。', '决策-行动策略', 18),
('model', '未来可选性', '当前选择→获得/失去的未来选项→积累的能力和资源', '评估一个选择好不好，不只看眼前的收益，更看它打开了多少扇未来的门。好的选择会带来更多的未来选择、更强的能力、更多的资源，推动人生进入下一阶段。', '适用场景：职业选择、学习方向、人际关系、城市选择——任何影响长期发展的决策。', '决策-行动策略', 19),
('model', '真实需求测试', '表面欲望→真实需求→短期舒适vs长期价值→匹配度', '当你想要什么时，先问自己：这是表面的欲望，还是真正的需求？是短期舒适的逃避，还是长期价值的追求？真正的满足来自真实需求被满足，而不是欲望被即时满足。', '适用场景：消费决策、职业选择、关系判断——任何"想要但不确定是否应该"的场景。', '决策-行动策略', 20),

-- ========== 决策模型：情绪与认知 ==========
('model', '情绪-现实分离', '情绪标签→身体/感觉观察→事实→行动', '当恐惧、焦虑、羞耻或痛苦驱动决策时，先做三步：1）给情绪命名（"我现在感到焦虑"）；2）观察身体感觉（心跳加速、肩膀紧绷）；3）列出客观事实。情绪是信息，不是现实。基于事实行动，而不是基于情绪反应。', '适用场景：任何被情绪主导的决策——恐惧、愤怒、内疚、焦虑、羞耻。', '决策-情绪认知', 21),
('model', '魔鬼代言人', '偏好选项→最强反对论点→证据检查→修正', '当你倾向于某个选择时，故意扮演反对者：如果要反驳自己，最强的论点是什么？这个论点有证据支持吗？如果有，需要修正原来的判断。这能有效对抗确认偏误。', '适用场景：重大决策前的自检、团队讨论中避免群体思维、投资判断。', '决策-情绪认知', 22),
('model', '三人顾问', '问三个背景不同的人→比较建议→识别激励和偏差→提取有用信号', '不要只听一个人的建议。找三个背景不同的人（如同行、跨行业朋友、有类似经历的人），比较他们的建议，识别每个人的激励和潜在偏差，提取真正有用的信号。', '适用场景：重大决策、职业选择、关系困惑——任何需要外部视角但又不能完全依赖他人判断的场景。', '决策-情绪认知', 23),

-- ========== 决策模型：博弈论 ==========
('model', '囚徒困境', '个体短期背叛可能优于合作，但互相背叛使所有人境况更差', '经典的博弈困境：如果双方都合作，各得3分；一方背叛一方合作，背叛者得5分，合作者得0分；双方都背叛，各得1分。理性推导导致互相背叛，但合作才是整体最优。解法：重复博弈、声誉机制、可信承诺。', '适用场景：信任、团队合作、价格战、合作伙伴关系——任何涉及"合作还是自利"的选择。', '决策-博弈论', 24),
('model', '纳什均衡', '如果其他玩家保持策略不变，每个玩家会怎么做？', '检查一个计划是否稳定：假设其他人不动，我有没有动机单方面改变？如果所有人都没有动机改变，就达到了纳什均衡。但纳什均衡不一定是全局最优（如囚徒困境）。', '适用场景：团队分工、谈判策略、市场竞争、任何多人互动场景。', '决策-博弈论', 25),
('model', '逆向归纳法', '从最终阶段开始逆向推理，倒推现在该做什么', '不要从现在往后想，而是从终点往回推。先想最后签约前对方最在意什么，再倒推我现在需要准备什么。这在顺序决策中特别有效，能避免"走一步看一步"的被动。', '适用场景：谈判、职业规划、项目倒推、承诺问题。', '决策-博弈论', 26),
('model', '可信承诺', '只有可信且伪装代价高昂的承诺才有意义', '空口承诺没有约束力。真正有效的承诺需要"代价"——公开承诺、定金、合同、可见的约束。同样，威胁要可信也需要让对方知道你"说到做到"的代价很高。', '适用场景：谈判、合作协议、自我约束、激励机制设计。', '决策-博弈论', 27),
('model', '信号与筛选', '高成本信号揭示真实意图；设计测试让人自我揭示', '信号：对方愿意付出什么代价，就说明他有多认真。筛选：设计一个测试或门槛，让不同类型的人自然区分开来。不要只听对方说什么，要看他做什么、愿意付出什么。', '适用场景：招聘、合伙、投资判断、关系评估——任何需要判断对方真实意图的场景。', '决策-博弈论', 28),
('model', '委托代理', '行动方可能与委托方激励不一致，需要监督和对齐奖励', '当别人替你做事时，他们的利益可能和你不同。外包团队按工时收费，未必关心效率；员工追求稳定，未必愿意冒险。解法：对齐奖励（结果导向）、里程碑检查、明确问责。', '适用场景：管理下属、外包合作、投资管理、任何"委托他人执行"的场景。', '决策-博弈论', 29),

-- ========== 社交模型：基础对话 ==========
('model', '对话飞轮', '观察提问→积极倾听→适度自我袒露→真诚追问', '所有日常对话的底层引擎。观察对方的状态或环境，提出真诚的问题；认真倾听后，适度分享自己的相关经历；然后再次真诚追问。这个循环不断转动，对话自然深入。', '适用场景：任何需要拉近关系、保持对话流动的日常聊天。', '社交-基础对话', 30),
('model', '积极倾听(3F)', '听事实(Fact)→听感受(Feeling)→听真实意图(Focus)', '倾听不是等着轮到自己说话。先听对方说了什么事实，再听他表达了什么感受（注意"总是、从不"等词），最后听他真正想表达什么。回应前先完成这个三阶诊断。', '适用场景：对方表达含糊、话里有话、带有情绪时。', '社交-基础对话', 31),
('model', '上堆与下切', '上堆提炼观点和动机；下切追问细节和感受', '对话浮于表面时用下切：追问具体细节、感受、事实。对方表达太多细节时用上堆：提炼核心观点、探讨动机、展望未来。灵活切换让对话既有深度又有方向。', '适用场景：对话卡在表面需要深入，或者对方说太多需要提炼重点时。', '社交-基础对话', 32),

-- ========== 社交模型：破冰与闲聊 ==========
('model', 'FORD闲聊模型', '聊家庭/朋友→职业/学业→休闲→梦想', '和不熟的人需要安全话题时，按FORD顺序展开：Family（家庭，注意边界）、Occupation（职业）、Recreation（休闲娱乐）、Dreams（梦想目标）。关系不深时不问隐私家庭问题。', '适用场景：初次见面、聚会冷场、电梯偶遇、和不熟的人需要安全话题。', '社交-破冰闲聊', 33),
('model', '即兴发言公式', '赞同+细节+谦虚 / 感受+回顾+愿景', '被突然点名发言时的万能结构：先赞同前面的人说的话，加一点自己的细节观察，最后谦虚收尾。或者：感谢+感受+愿景。关键：不要慌，三秒内开口。', '适用场景：被突然点名发言、祝酒词、领奖感言、会议临时发言。', '社交-破冰闲聊', 34),

-- ========== 社交模型：拒绝与边界 ==========
('model', '非暴力沟通(NVC)', '观察(不评判)→感受→需要→请求(具体可执行)', '表达不满时避免指责。四步：1）只说观察到的事实（"你这周迟到了三次"而非"你总是迟到"）；2）说出自己的感受（"我感到担心"）；3）表达背后的需求（"因为我需要团队的节奏一致"）；4）提出具体请求（"以后能提前10分钟到吗？"）。', '适用场景：亲密关系、重要合作中需要表达不满但不想激化矛盾时。', '社交-拒绝边界', 35),
('model', 'DESC坚定边界', '描述事实→表达影响→明确要求→确认后果', '当对方反复越界时，用DESC做一次正式但非攻击的沟通：描述具体事实（"这周你三次临时把任务转给我"），表达对你的影响（"我很难安排自己的进度"），明确你的要求（"以后请至少提前一天"），确认后果或协议（"紧急情况我们单独协调"）。', '适用场景：同事反复越界、朋友借钱不还、家人过度干涉——需要坚定但不攻击地设立边界。', '社交-拒绝边界', 36),
('model', '三明治反馈法', '肯定→建议→鼓励', '批评时先肯定人或做得好的部分，再说具体需要改进的行为，最后以鼓励或信任结尾。这比直接批评更容易被接受，但要注意：肯定要真诚，不能敷衍。', '适用场景：向上/向下反馈、朋友间提建议、任何需要"说不好听的话"但想维护关系的场景。', '社交-拒绝边界', 37),

-- ========== 社交模型：情绪支持 ==========
('model', '称赞模型', '具体行为→推断特质→说明影响', '称赞要具体到行为、推断特质、说明影响。不要只说"你真棒"，而是说"你刚才主动帮新人梳理流程（行为），说明你很有责任心（特质），这让整个团队效率提高了不少（影响）"。对长辈重细节、责任感、靠谱、判断力。', '适用场景：想表达欣赏、回应对方好表现、维护关系。', '社交-情绪支持', 36),
('model', '接受称赞模型', '用延伸/归因/衬托/调侃法大方收下', '被夸奖时不要尴尬否认，用五种方法大方收下并回馈情绪价值：1）延伸法（"你旁边站着的不就是将来的大学生嘛"）；2）归因法（"多亏了您指导"）；3）衬托法（"有幸跟优秀的人做同事"）；4）找补法（自嘲一个小缺点）；5）调侃法（"漂亮的眼睛看谁都漂亮"）。核心：不要否认，要接住并回馈。', '适用场景：被长辈夸、被领导认可、被朋友称赞、被陌生人夸外貌——任何被夸奖的场景。', '社交-情绪支持', 37),
('model', '安慰模型', '表达支持→倾听故事→反馈情感→反馈认知', '安慰时不要说"至少…"、不要说教、不要匆忙给解决方案。先表达"我在"，然后让他倾诉，反馈你感受到他的情绪（"这件事换谁都会难受"），最后可以温和地反馈一个不同的视角。', '适用场景：朋友遭遇挫折、同事项目失败、家人生病——对方需要情感陪伴而非解决方案时。', '社交-情绪支持', 38),
('model', '鼓励模型', '描述好做法→请教方法→说出启发', '鼓励不是空洞的"加油"。先描述你观察到对方做得好的具体行为，然后请教他是怎么做到的，最后说出这对你的启发。这比"你真棒"有力得多。', '适用场景：对方在困难中坚持、刚完成挑战、需要信心支持时。', '社交-情绪支持', 39),

-- ========== 社交模型：冲突修复 ==========
('model', 'LARA降级冲突', '倾听→确认→回应→补充', '双方情绪激动时，先降级：认真倾听不打断，确认对方的感受是合理的（"我理解你为什么担心"），然后平静地回应你的看法，最后补充建设性的方案。', '适用场景：双方即将争吵、会议中意见激烈对立、亲密关系冲突升级。', '社交-冲突修复', 40),
('model', '关系修复(REPAIR)', '识别→共情→承担个人责任→行动→邀请回应→安抚', '当你意识到自己伤了对方时：先识别伤害的存在，表达共情，承担自己那部分责任（"这是我的问题"），提出具体行动，邀请对方回应，最后安抚关系。', '适用场景：说错话、做错事、误解了对方意图后需要修复关系时。', '社交-冲突修复', 41),

-- ========== 社交模型：职场表达 ==========
('model', 'SBI反馈模型', '情境(Situation)→行为(Behavior)→影响(Impact)', '给出具体、不攻击人格的反馈：在什么情境下，你观察到什么具体行为，这个行为产生了什么影响。避免"你总是…""你这个人…"的表述。', '适用场景：职场绩效反馈、同事间行为纠正、朋友间需要指出问题。', '社交-职场表达', 42),
('model', 'PREP结构化表达', '观点(Point)→理由(Reason)→例子(Example)→重申观点(Point)', '需要清晰阐述观点时：先亮观点，再给理由，举一个具体例子，最后重申观点。简单有力，适合开会、面试、辩论。', '适用场景：会议发言、面试回答、辩论论证、任何需要快速说服的场景。', '社交-职场表达', 43),
('model', 'SCQA提案模型', '情境(Situation)→冲突(Complication)→问题(Question)→答案(Answer)', '向决策者提建议时：先描述现状（S），再指出冲突或问题（C），引出核心问题（Q），最后给出你的答案（A）。让听众自然跟随你的逻辑。', '适用场景：项目提案、汇报方案、写邮件请求资源、面试案例分析。', '社交-职场表达', 44),
('model', 'GROW教练模型', '目标(Goal)→现状(Reality)→选项(Options)→意愿(Will)', '对方迷茫时引导他自己做决定：你希望达到什么目标？现在的情况是什么？有哪些可选做法？你愿意先试哪一步？不给建议，只提问引导。', '适用场景：下属/朋友陷入迷茫，需要引导对方自己思考而不是直接给建议。', '社交-职场表达', 45),

-- ========== 社交模型：性格应对 ==========
('model', 'EASE内向者应对', '鼓励→认可→分享→轻松提问', '对方话少但礼貌时：先鼓励他说（"你刚才说的那个很有意思"），认可他的贡献，适度分享自己的经历降低压力，然后用轻松的方式提问。不要追问太多。', '适用场景：和内向者、谨慎的人、新加入团队的人交流。', '社交-性格应对', 46),
('model', 'FIRE外向者应对', '感受→兴趣→关联自我→拓展', '对方语速快、能量高时：跟上他的节奏，表达你的感受（"哈哈听起来不错"），表达兴趣，关联到自己的经历，然后拓展话题。', '适用场景：和热情外向、喜欢分享、精力充沛的人交流。', '社交-性格应对', 47),

-- ========== 应变模型：认知分析 ==========
('model', 'OODA循环', '观察→定向→决定→行动', '高压场景下的快速决策循环：先观察现场情况，再定向判断威胁和对方意图，然后快速决定说什么/做什么，最后沉着行动。关键：不要卡在分析阶段，3秒内给出第一反应。', '适用场景：突发状况、快速变化的环境、需要即时反应的场景。OODA同时出现在决策和应变模块中——快速决策能力在两个领域都关键。', '应变-认知分析', 48),
('model', 'STOP模型', '停下(Stop)→思考(Think)→观察(Observe)→计划(Plan)', '高压场景下的第一步是"停下来"。不要慌，先深呼吸。然后思考现在是什么局面，观察有什么可用资源和信息，最后制定分步计划。', '适用场景：任何突发状况的第一反应——先STOP，再行动。', '应变-认知分析', 49),
('model', '5W1H快速扫描', '3秒内扫描Who/What/When/Where/Why/How', '高压场景下快速梳理事件全貌：谁？什么事？什么时候？在哪？为什么？怎么办？理清思路再开口，避免慌乱中说出后悔的话。', '适用场景：被突然质问、突发事故、需要快速整理信息的场景。', '应变-认知分析', 50),
('model', '最小信息原则', '不确定时只说最少必要的内容', '越解释漏洞越多。不确定时只说最必要的信息，不主动补充细节，不自作聪明多解释。等对方追问再逐步释放信息。', '适用场景：被质问时信息不完整、不想暴露更多细节、需要争取时间思考时。', '应变-认知分析', 51),
('model', '意图分层法', '表层问题→真实目的→底层动机', '对方说的话可能不是他真正想要的。把他的表达拆成三层：表面在问什么？真实目的是什么？底层动机是什么？回答"目的"而不是回答"问题"。', '适用场景：对方话里有话、追问背后有其他目的、需要识破真实意图时。', '应变-认知分析', 52),

-- ========== 应变模型：沟通策略 ==========
('model', '重构叙事', '改变对方对事件的解读框架', '不是在藏钱，是在给你准备惊喜的预算。不是迟到，是提前确认了会议改期。关键：改变"框架"而不是改变"事实"，让同一件事有不同但合理的解读。', '适用场景：被误解、需要改变对方对事件的看法、危机公关。', '应变-沟通策略', 53),
('model', '情绪降温话术', '主动延迟回答赢得缓冲时间', '高压场景下不要急着回答。用"你说得对，让我整理一下思路""这个问题很重要，我认真想想"来争取思考时间。沉默比说错话好。', '适用场景：被突然质问、情绪激动时、需要时间思考策略时。', '应变-沟通策略', 54),
('model', '模糊回应策略', '用模糊但合理的话回应，不给明确细节锚点', '不确定该说什么时，用模糊但不会出错的话回应。"大概就是那样""差不多吧""具体细节我回头确认"——给自己留退路。', '适用场景：不想撒谎但也不能说实话、信息不完整、需要保护隐私时。', '应变-沟通策略', 55),
('model', '递延回应法', '不当场答，换时间或场景', '不一定要当场给答案。"我整理一下，晚点给你完整信息""这个问题我们找个时间专门聊"——把战场转移到你更有准备的时间和地点。', '适用场景：当场回答不利、需要时间准备、场景不适合深入讨论时。', '应变-沟通策略', 56),

-- ========== 应变模型：危机公关 ==========
('model', 'AER危机模型', '承认(Acknowledge)→解释(Explain)→补救(Remedy)', '犯错后的标准应对：先承认现状/错误（不要否认），再解释原因（不找借口），最后提出具体补救方案。速度要快，态度要诚恳。', '适用场景：职场失误、明显犯错、需要快速止损的场景。', '应变-危机公关', 57),
('model', '3C危机原则', '关注(Concern)→承诺(Commitment)→控制(Control)', '快速平息对方情绪：先表达你理解他的感受，再做出可信的承诺，最后掌握后续的主导权。让对方感到"有人在处理"。', '适用场景：客户投诉、团队危机、需要快速稳定局面时。', '应变-危机公关', 58),
('model', '降级处理法', '把大问题描述为局部偏差', '不要让问题看起来比实际更严重。把"系统崩溃"说成"某个功能暂时受影响"，把"重大失误"说成"一个小偏差正在修复"。控制严重程度的感知。', '适用场景：向上汇报、对外沟通、危机公关——需要控制恐慌情绪时。', '应变-危机公关', 59),

-- ========== 应变模型：心理博弈 ==========
('model', '扑克脸原则', '控制慌张信号，让表情和语气先稳下来', '高压场景下，你的表情和语气比内容更重要。控制手抖、目光回避、结巴、过度解释等"慌张信号"。先稳住自己，再开口说话。', '适用场景：被质问、面试、谈判、任何需要表现镇定的场景。', '应变-心理博弈', 60),
('model', '先发制人', '在对方开口前主动说出来，抢占叙事主动权', '如果你知道对方要问什么，不如先说出来。主动承认比被动被发现好得多。一旦你的叙事框架被接受，对方的质疑就成了"补充"而非"推翻"。', '适用场景：你知道某个问题即将被提出、需要主动控制叙事方向时。', '应变-心理博弈', 61),
('model', '三秒原则', '深吸一口气，三秒内给出第一句话', '高压场景下，打破沉默比说完美更重要。深吸一口气，在三秒内给出第一句话——即使是"让我想想"也比沉默好。沉默越久，压力越大。', '适用场景：任何需要快速反应的高压场景——面试、质问、突发状况。', '应变-心理博弈', 62),

-- ========== 元认知模型 ==========
('model', '场景识别模型', '先判断问题属于冲突/决策/表达/情绪哪一类', '遇到问题时先不急着用策略，而是先分类：这是信息问题、情绪问题、利益问题、还是关系问题？不同类别对应完全不同工具箱。', '适用场景：任何复杂情况的第一步，用于避免用错模型。', '元认知', 63),
('model', '模型选择器', '在多个模型之间选择最合适的一个或组合', '同一个问题往往需要多个模型组合，例如：先OODA应变，再DESC设边界，再PREP表达。核心能力是"选模型"，而不是"用模型"。', '适用场景：所有复杂场景（现实中90%问题需要组合使用）。', '元认知', 64),
('model', '信号识别模型', '识别对方行为背后的真实意图信号', '判断对方是在争信息、争权力、争情绪、还是争关系，从而决定你的应对方式。不要只看表面行为，要看底层驱动力。', '适用场景：沟通不清晰、对方行为有隐藏动机时。', '元认知', 65),

-- ========== 行动执行层 ==========
('model', '行动触发器', '定义什么时候必须行动而不是继续分析', '很多问题卡在"想太多不行动"。这个模型定义：出现哪些条件必须执行，而不是继续思考。设置"分析截止线"——超过这个时间就必须动。', '适用场景：拖延、犹豫、过度分析。', '行动执行', 66),
('model', '执行最小单元', '把行动拆到无法再拖延的最小步骤', '不是"写报告"，而是"打开文档写第一段"。不是"找新工作"，而是"更新简历第一行"。降低行动门槛到极限，让启动成本趋近于零。', '适用场景：拖延症、启动困难、任何"知道该做但一直没做"的事。', '行动执行', 67),
('model', '反馈闭环模型', '行动→结果→修正→再行动', '所有行动必须有反馈机制，否则模型无法进化。重点不是做，而是"做完知道对不对"。设置明确的回顾时间和评估指标。', '适用场景：学习、工作、习惯养成、任何需要持续改进的领域。', '行动执行', 68),

-- ========== 组织权力模型 ==========
('model', '决策权定位模型', '谁在决定？谁在影响？谁只是执行？', '在任何组织问题中，先画三层结构：决策者、影响者、执行者。你的策略永远是靠近决策层，而不是在执行层内卷。', '适用场景：职场晋升、资源争夺、项目推进。', '组织权力', 69),
('model', '影响力杠杆模型', '用信息/资源/关系/不可替代性影响决策', '影响力不是职位赋予的，而是来自杠杆：信息差、资源控制、关键节点位置、不可替代技能。找到你的杠杆点，放大它。', '适用场景：想提升话语权但职位没变时。', '组织权力', 70),
('model', '隐性规则识别模型', '找出组织中"写不出来但真实存在"的规则', '真正决定结果的往往不是明文制度，而是隐性规则：谁真正说了算、什么行为被奖励、什么行为被惩罚、什么人不能得罪。', '适用场景：新公司适应期、晋升失败分析、组织文化理解。', '组织权力', 71),

-- ========== 情绪系统模型 ==========
('model', '情绪功能分析模型', '每种情绪对应一个功能：保护/推动/信号', '焦虑=提醒不确定风险；愤怒=边界被侵犯；羞耻=社会评价威胁；内疚=道德标准未达标。情绪不是问题，是信号系统——读懂信号比压制情绪更重要。', '适用场景：情绪困扰、内耗、焦虑、任何"知道自己不该这样但控制不了"的场景。', '情绪系统', 72),
('model', '情绪延迟处理模型', '情绪先不解决，延后再处理', '高情绪状态下不做决策。先延迟处理，让系统冷却。可以用"我现在需要20分钟整理思路"来争取时间。', '适用场景：吵架、冲动决策、焦虑状态、任何"情绪上头"的时刻。', '情绪系统', 73),
('model', '情绪分流模型', '区分可行动情绪vs不可行动情绪', '能解决的问题→行动；不能解决的→接受或释放。避免情绪无限循环：如果能做点什么就做，如果做不了就放手。', '适用场景：长期焦虑、无力感、反复纠结。', '情绪系统', 74),

-- ========== 信息系统模型 ==========
('model', '信息完整性模型', '判断信息是否足够做决策', '缺关键变量的信息决策必然错误。在做决定前问：我是否掌握了影响结果的关键信息？如果缺失，是去收集还是用概率做临时决策？', '适用场景：汇报、决策、谈判——任何信息可能不完整的场景。', '信息系统', 75),
('model', '信息对称性模型', '谁掌握更多真实信息谁更有优势', '减少信息不对称是提升控制力的核心方法。多渠道获取信息、直接接触信息源头、建立信息网络。', '适用场景：谈判、职场政治、竞争场景。', '信息系统', 76),
('model', '信息过滤模型', '识别信息在传递过程中被谁修改', '信息每经过一层都会被过滤或重写。要追溯源头，交叉验证，识别"谁在给你什么版本的信息"以及"他为什么给你这个版本"。', '适用场景：组织沟通混乱、谣言判断、信任评估。', '信息系统', 77),

-- ========== 人性行为模型 ==========
('model', '利益驱动模型', '人行为主要由收益/成本决定', '所有复杂行为最终都可以拆成利益结构，而不是道德解释。问"他这样做对他有什么好处"比问"他为什么这样对我"更有建设性。', '适用场景：冲突分析、动机判断、理解"不可理喻"的行为。', '行为底层', 78),
('model', '地位信号模型', '很多行为是在争取社会地位', '抢功、打压、炫耀、贬低他人，本质都是地位竞争信号。理解这一点，就不会把对方的行为个人化——他不是针对你，是在争夺位置。', '适用场景：职场冲突、人际关系中的竞争行为。', '行为底层', 79),
('model', '风险规避模型', '人更怕损失而不是追求收益', '解释为什么很多人保守、拒绝变化、抗拒责任。损失厌恶是人类本能——要说服别人冒险，需要让"不行动"的风险比"行动"的风险更可见。', '适用场景：理解他人决策、说服他人、推动变革。', '行为底层', 80),

-- ========== 不确定性处理模型 ==========
('model', '信息不全决策模型', '信息不完整时如何先行动', '现实中大多数决策都在信息不完整状态下发生。不是等信息齐了再做，而是用最小可信信息做临时决策，并预留修正空间。', '适用场景：紧急决策、临时任务、突发情况。', '不确定性处理', 81),
('model', '渐进确认模型', '边做边补信息而不是一次性收集完', '先做一个低成本版本，然后通过反馈补充信息，逐步逼近正确答案。这比"等想清楚再动手"更高效。', '适用场景：项目推进、复杂问题解决、创业验证。', '不确定性处理', 82),
('model', '信息可信度分层', '区分一手信息/二手信息/推测', '所有信息分三层：直接观察 > 可信来源转述 > 推测和传言。决策权重依次降低。不要把推测当事实来决策。', '适用场景：谣言判断、组织信息混乱、媒体信息筛选。', '不确定性处理', 83),

-- ========== 冲突管理模型 ==========
('model', '冲突分级模型', '冲突分为5级并对应不同处理方式', '0级无冲突→正常沟通；1级误解→解释澄清；2级分歧→讨论协商；3级对立→结构化表达；4级情绪化→降级沟通；5级破裂→停止接触。判断当前级别，选择对应策略。', '适用场景：所有人际冲突的动态判断和策略选择。', '冲突管理', 84),
('model', '冲突降级路径', '从对抗→事实→目标→合作', '任何冲突都可以逐步降级：先停止情绪对抗，再对齐事实，然后重建共同目标，最后寻找合作方案。关键：每一步都要对方跟上，不能单方面跳步。', '适用场景：争吵、会议冲突、团队对立。', '冲突管理', 85),
('model', '冲突冻结模型', '暂时停止冲突推进避免升级', '当冲突过热时，主动暂停讨论。"我们先冷静一天，明天再聊"——防止关系永久损伤。冻结不是逃避，是给双方恢复理性的空间。', '适用场景：高情绪冲突、亲密关系争吵、团队激烈对立。', '冲突管理', 86),

-- ========== 责任系统模型 ==========
('model', '责任边界模型', '明确责任输入/输出/依赖', '任何任务必须明确：谁负责输入？谁负责执行？谁负责验收？谁负责结果？否则必然扯皮。在项目开始时就写清楚，而不是事后争论。', '适用场景：跨部门合作、项目管理、团队分工。', '责任系统', 87),
('model', '归因拆解模型', '区分能力问题/系统问题/资源问题/运气问题', '失败不能简单归因于"人不行"。要拆解：是能力不足？系统流程有缺陷？资源不够？还是运气因素？不同原因对应完全不同的解决方案。', '适用场景：复盘失败、绩效分析、问题诊断。', '责任系统', 88),
('model', '责任外溢识别模型', '识别责任是否被无形扩大', '任务范围在过程中是否被悄悄扩大但责任没有同步调整？"顺便把这个也做了"往往就是责任外溢的开始。', '适用场景：工作量过载、被压榨、项目范围蔓延。', '责任系统', 89),

-- ========== 人际经济模型 ==========
('model', '关系收益模型', '任何关系都有成本和收益', '人际关系不是情感抽象，而是持续的资源交换系统（时间、情绪、资源、信息）。健康的关系是双向流动的，长期单向付出必然失衡。', '适用场景：人际关系评估、社交投资决策。', '人际经济', 90),
('model', '不对等关系识别', '长期单向付出关系是风险结构', '如果长期只有输出没有输入，这种关系会逐渐失衡甚至反噬。识别并调整：要么建立对等，要么降低投入。', '适用场景：朋友、同事、上下级关系判断。', '人际经济', 91),
('model', '关系维护阈值', '定义关系维持最低投入标准', '不是所有关系都值得同等投入。定义最低维护线：哪些关系需要深度投入，哪些只需维持基本联系，哪些可以放手。', '适用场景：社交精简、时间管理、精力分配。', '人际经济', 92),

-- ========== 效率系统模型 ==========
('model', '时间压缩模型', '时间不足时如何保证最低可用输出', '在时间不足情况下优先保证核心价值输出，而不是完整性。问"如果只能做一件事，做哪件？"先交付80分的版本，再迭代。', '适用场景：临时任务、紧急汇报、deadline逼近。', '效率系统', 93),
('model', '任务优先级动态模型', '优先级随时间和风险变化', '任务优先级不是固定的，会随外部变化动态调整。今天不紧急的事明天可能突然变紧急。定期重新评估，而不是设完优先级就不管了。', '适用场景：多任务管理、项目排期。', '效率系统', 94),
('model', '能量匹配模型', '任务复杂度必须匹配当前精力状态', '低能量做高复杂任务必然失败。把最重要的事放在精力最好的时段，低精力时段处理机械性工作。', '适用场景：疲劳状态工作安排、时间管理。', '效率系统', 95),

-- ========== 灰区行为模型 ==========
('model', '模糊边界操作', '在规则边界内最大化自身利益', '现实中很多行为不是违规，而是在规则允许范围内优化自身结果。理解这一点，既保护自己不被"合规地伤害"，也学会在规则内争取最大利益。', '适用场景：职场博弈、资源争取、合同谈判。', '灰区行为', 96),
('model', '责任稀释策略识别', '识别对方是否在稀释责任', '当多人共同负责时，每个人都会倾向降低自身责任份额。识别这种行为，提前明确分工和问责机制。', '适用场景：团队项目失败分析、跨部门协作。', '灰区行为', 97),
('model', '信息选择性暴露', '只展示对自己有利的信息', '人会主动隐藏不利信息、展示有利信息，这是默认行为。识别这一点：看对方没说什么，比看对方说了什么更重要。', '适用场景：谈判、汇报、信息评估。', '灰区行为', 98),

-- ========== 决策模型：补充 ==========
('model', '价值观过滤', '价值观→不可妥协项→权衡取舍→选择', '当决策涉及人生方向、职业选择、关系判断时，先列出你最核心的3-5个价值观（如成长、自由、安全、家庭），标记哪些是不可妥协的，然后看每个选项是否满足不可妥协项。不满足的直接排除。', '适用场景：人生决策、职业选择、关系判断、身份认同相关的选择。', '决策-经典框架', 99),
('model', '期望值', '结果→概率→价值/成本→经风险调整后的选择', '把每个选项的可能结果列出来，估计每个结果发生的概率，计算加权期望值。不只是看"最好的结果"，而是看"平均来看哪个更好"。', '适用场景：投资决策、创业评估、保险选择——任何有可衡量上下行风险的不确定决策。', '决策-经典框架', 100),
('model', '机会成本', '如果我选A，我放弃了什么？', '每个选择都有代价——不是你花了什么，而是你放弃了什么。接下这个项目，你放弃的是周末休息和准备考试的时间。把这个隐性成本显性化，再做决定。', '适用场景：时间分配、金钱使用、职业承诺——任何"选了A就做不了B"的场景。', '决策-经典框架', 101),
('model', '可逆门模型', '单向门vs双向门→决定速度→安全网', '决策分两种：不可逆的（单向门）要慎重，可逆的（双向门）要快速。大多数决策是双向门，可以先试再说。只有少数决策是真正的单向门，需要深思熟虑。', '适用场景：决定需要多少分析才足够——避免对可逆决策过度分析，对不可逆决策草率决定。', '决策-经典框架', 102),
('model', '事后复盘学习', '结果→决策质量→过程质量→教训', '决策结果出来后，回顾时要区分"决策质量"和"结果质量"。好的决策也可能有坏结果（运气差），坏决策也可能有好结果（运气好）。重点评估过程，而不是只看结果。', '适用场景：项目结束、季度回顾、重大事件后——任何需要从经验中学习的时刻。', '决策-经典框架', 103),
('model', 'Cynefin复杂性检查', '简单→复杂→繁杂→混沌→判断应对策略', '不是所有问题都用同一种方法。简单问题用最佳实践；复杂问题需要专家分析；繁杂问题需要实验；混沌问题需要先稳定再分析。判断问题属于哪个象限，选择对应策略。', '适用场景：不确定该用什么方法解决问题时——先判断问题类型，再选工具。', '决策-分析工具', 104),
('model', '决策日志', '背景→选项→假设→理由→预测→回顾日期', '每次重要决策都记录：当时的背景、考虑的选项、关键假设、选择理由、对结果的预测。设定回顾日期。长期积累后，你能发现自己决策模式中的盲点。', '适用场景：任何重要决策——养成记录习惯，长期提升决策质量。', '决策-行动策略', 105),
('model', '建议过滤', '谁受益→证据质量→经验匹配度→偏差检查', '别人的建议不一定适合你。过滤四步：1）这个建议对他有什么好处？2）有证据支持吗？3）他的经验和你的情况匹配吗？4）他有什么潜在偏差（风险偏好、行业偏见）？', '适用场景：被他人建议淹没、需要判断哪些建议值得采纳时。', '决策-情绪认知', 106),
('model', '2x2决策地图', '风险×回报，或面对×回避', '把选项放在2x2矩阵中：横轴是风险，纵轴是回报。高回报低风险的优先做，高回报高风险的试一试，低回报高风险的避免。或者用"面对×回避"来判断你是在追求成长还是在逃避恐惧。', '适用场景：选项优先级排序、判断自己是在追求还是在逃避。', '决策-分析工具', 107),
('model', '核心-20模型', '识别造成80%影响的20%核心矛盾', '问题看起来很大很复杂时，问自己：哪20%的因素造成了80%的影响？找到那个核心矛盾，集中精力解决它，其他的自然会改善。', '适用场景：问题感觉过于庞大、不知从何下手时。', '决策-分析工具', 108),
('model', '三分之二时机规则', '预期决策窗口→在三分之二时间点收集信息→提前决定', '如果一个决策有三周的窗口，在第二周结束前就要决定。不要等到最后一刻被压力推着走。在三分之二时间点，你已经收集了大部分信息，但还没有deadline焦虑。', '适用场景：有时间窗口的决策——避免拖延到最后一刻。', '决策-行动策略', 109),
('model', '系统脱敏', '小暴露→稍高难度暴露→反馈→下一级', '当恐惧阻碍行动时，不要一步到位。先做一个低风险的小暴露（如害怕被拒绝就先问路），成功后逐步提高难度。每次暴露后给大脑一个"其实没那么危险"的信号。', '适用场景：社交恐惧、演讲恐惧、任何被恐惧阻碍需要逐步克服的场景。', '决策-行动策略', 110),
('model', '情景演练模型', '模拟高压情境→练习反应→回顾→调整', '害怕某个场景？先在安全环境中模拟它。面试前找朋友模拟面试，谈判前预演对方可能的反应。通过演练把"未知恐惧"变成"已知挑战"。', '适用场景：面试准备、演讲准备、谈判准备——任何需要在高压下表现的场景。', '决策-行动策略', 111),
('model', '选择回顾清单', '真实需求/未来可选性/事实/假设/偏差/风险/备用计划/止损/下一步', '在给出最终建议或做最终决定前，用这个清单做最后检查：是否满足真实需求？是否扩大了未来选项？事实和假设分清了吗？有哪些偏差风险？有备用计划吗？止损线在哪？下一步是什么？', '适用场景：重大决策前的最终检查。', '决策-行动策略', 112),
('model', '投资组合策略', '稳定基础→多个小型赌注→回顾→再平衡', '不要把所有赌注放在一个地方。80%放在稳定的基础（主业、核心能力），20%分散在多个小赌注（副业、新技能、新人脉）。定期回顾，根据结果再平衡。', '适用场景：人生规划、职业发展、学习投资——任何需要长期布局的领域。', '决策-行动策略', 113),
('model', '投资组合分配', '核心稳定→增长性赌注→高风险实验→跨维度资源分配', '资源分配三层：核心层（必须维持的）、增长层（有潜力的）、实验层（高风险高回报的）。在时间、精力、金钱三个维度上分别做分配，确保不会因为一个失败而全盘崩溃。', '适用场景：职业组合、学习计划、投资策略。', '决策-行动策略', 114),
('model', '黑天鹅模型', '低概率事件→高影响后果→系统脆弱性分析→尾部风险暴露', '有些事件概率很低但影响巨大（如疫情、行业剧变、关键人离职）。不要只优化"正常情况"，还要检查系统在极端情况下的脆弱性。问自己：如果最不可能的事发生了，我能承受吗？', '适用场景：风险规划、系统设计、人生重大决策——任何"失败将是灾难性的"场景。', '决策-风险管理', 115),

-- ========== 社交模型：补充 ==========
('model', '开场提问模型', '观察现场/共同点/称赞→询问观点/方法/经历/兴趣', '初次见面或冷场时，先观察现场找到共同点或值得称赞的地方，然后用开放性问题展开："你是怎么开始做这个的？""你对这个怎么看？"避免问隐私、争议、负面八卦。', '适用场景：初次见面、聚会冷场、加入不熟悉的群体。', '社交-破冰闲聊', 116),
('model', '讲故事模型', '5W1H + 目标→努力→困难→结果', '分享经历时用这个结构：谁、何时、何地、什么事、为什么、怎么做，然后展开为目标→努力→困难→结果。制造"接话钩子"让对方能追问。', '适用场景：对方问"你最近怎么样""当时发生了什么"，或者你想分享经历但不想显得自恋。', '社交-基础对话', 117),
('model', 'CEIT随性社交', '现状(Current)→解释(Explain)→邀请(Invite)→轻松语气(Tone)', '别人随口问"最近怎么样""忙不忙"时，不要回答"还行"就结束。用CEIT：说现状，简单解释，邀请对方分享，保持轻松语气。', '适用场景：电梯偶遇、走廊碰面、别人随口问候时。', '社交-破冰闲聊', 118),
('model', 'AQST随机问答', '确认兴趣(Acknowledge)→追问(Question)→分享经历(Share)→轻松语气(Tone)', '对方分享了一件小事时，不要只说"哦"。确认你听到了，追问细节，分享自己的相关经历，保持轻松语气。让对话自然流动。', '适用场景：对方分享日常小事，你想延续轻松氛围。', '社交-破冰闲聊', 119),
('model', '拒绝模型', '拖延答复/三明治拒绝/破唱片法/直接拒绝+理由', '拒绝不是只有"不"一种方式。五种策略：1）拖延答复（"让我想想"）；2）三明治拒绝（肯定→拒绝→补偿）；3）破唱片法（重复立场不解释）；4）用"为什么"替代直接"不"；5）直接拒绝+简洁理由。根据关系和场景选择。', '适用场景：对方提出让你为难的请求，需要保护自己边界时。', '社交-拒绝边界', 120),
('model', 'DEAR请求模型', '描述(Describe)→表达(Express)→请求(Ask)→强化(Reinforce)', '向对方提出重要但可能被拒的请求时：描述具体情境，表达你的感受和需求，明确提出请求，最后强化（说明对方配合的好处或你的感激）。', '适用场景：向上级请求资源、向伴侣提出重要需求、任何需要说服对方同意的场景。', '社交-拒绝边界', 121),
('model', 'SAFE紧张化解', '共情(Sympathize)→轻轻提问(Ask lightly)→风趣放松(Funny/Relax)→鼓励赋能(Encourage/Empower)', '对方在社交中明显紧张、手足无措时：先共情（"第一次都会紧张"），轻轻提问转移注意力，用幽默缓解气氛，最后鼓励他。', '适用场景：新同事紧张、朋友社交焦虑、有人在公开场合说错话后尴尬。', '社交-情绪支持', 122),
('model', 'RELAX尴尬化解', '关联(Relate)→共情(Empathize)→轻度重构(Light reframe)→避免否定感受→扩展(eXpand)', '对方当众出糗、被调侃、觉得自己丢脸时：关联到自己的类似经历，表达共情，轻度重构事件（"其实没那么严重"），不要否定他的感受，然后自然扩展到其他话题。', '适用场景：朋友出糗、同事失误、有人在公开场合感到尴尬。', '社交-情绪支持', 123),
('model', 'ACT行动促动', '接纳(Accept)→切小难度(Cut difficulty)→触发微行动(Trigger action)', '对方因恐惧、拖延而犹豫不决时：先接纳他的感受（"犹豫是正常的"），把任务切到最小（"先试1分钟就行"），触发一个微小行动。不说教，只推一把。', '适用场景：朋友拖延、同事犹豫、任何需要推力而非说教的场景。', '社交-情绪支持', 124),
('model', '感谢模型', '具体帮助→对自己的影响→真诚感谢', '感谢不要只说"谢谢"。说清楚：你帮了我什么（具体），这对我产生了什么影响（价值），我真的很感激（真诚）。让对方感到被重视。', '适用场景：接受帮助后、收到礼物后、别人为你做了什么事后。', '社交-情绪支持', 125),
('model', '求助模型', '明确目的→已尝试的方法→提出具体诉求→事后感谢', '求助时不要说"帮帮我"。先说清楚你的目的，再说你已经尝试过什么，然后提出具体诉求（"你能帮我看看这个方案的第三部分吗？"），事后真诚感谢。', '适用场景：需要向他人寻求资源、信息、支持时。', '社交-情绪支持', 126),
('model', '批评建议模型', '私下场合→先肯定人→说具体行为→让对方复述→给建议→约定复盘', '必须指出对方问题时：选私下场合，先肯定人（不是行为），说具体行为（不攻击人格），让对方复述确认理解，问尝试过的方法，给建议，约定复盘时间。', '适用场景：必须指出对方问题且想维护关系时。', '社交-职场表达', 127),
('model', 'STAR经历模型', '情境(Situation)→任务(Task)→行动(Action)→结果(Result)', '回答行为面试题或讲述经历时：先描述情境，再说明你的任务，然后讲你采取的行动，最后说结果（用数据量化最佳）。', '适用场景：面试回答、述职汇报、讲述成功/失败经历。', '社交-职场表达', 128),
('model', 'BIFF书面冲突', '简短(Brief)→信息性(Informative)→友好(Friendly)→坚定(Firm)', '用文字处理冲突时（邮件、群聊、消息）：保持简短，只提供必要信息，语气友好但立场坚定。不争论、不情绪化、不给对方抓把柄。', '适用场景：处理敌意邮件、群聊争端、书面冲突。', '社交-职场表达', 129),
('model', 'BADNEWS困难消息', '缓冲(Buffer)→确认影响(Acknowledge impact)→清晰传达(Deliver clearly)→后续步骤(Next steps)→共情(Empathy)', '传达坏消息时：先缓冲（"先跟你同步一个情况"），确认你知道这会带来影响，清晰传达事实（不模糊），给出后续步骤，表达共情。', '适用场景：告知延期、拒绝请求、传达变更等令人失望的消息。', '社交-职场表达', 130),
('model', 'CLEAR异议处理', '确认顾虑(Confirm)→标注问题(Label)→解释(Explain)→邀请对齐(Ask/Align)→再次确认价值(Reaffirm)', '对方明确质疑或反对时：先确认他的顾虑是合理的，标注核心问题，解释你的方案如何应对，邀请他一起对齐方案，最后再次确认你对他的价值认可。', '适用场景：方案被质疑、提议被反对、需要化解对方的明确异议。', '社交-冲突修复', 131),
('model', 'PLAY幽默者应对', '接梗(Play along)→轻度调侃(Light tease)→添加细节(Add)→抛回问题(Yield question)', '对方频繁用梗、开玩笑时：接住他的梗，轻度调侃回应，添加有趣的细节，然后抛回问题。节奏跟上，不要正经过头。', '适用场景：和幽默的人聊天、饭局社交、轻松场合。', '社交-性格应对', 132),
('model', 'BALANCE理性者应对', '衔接(Bridge)→补充观点→逻辑(Logic)→避免争辩→中立语气→继续→舒缓(Ease)', '对方重视逻辑、爱说"从数据看"时：先衔接他的观点，用逻辑补充你的看法，避免情绪化争辩，保持中立语气，最后舒缓收尾。', '适用场景：和工程师、分析师、严谨型人格沟通。', '社交-性格应对', 133),
('model', 'SOFT冷淡者应对', '同步能量(Sync)→给予信息(Offer)→浮动试探(Float)→测试意愿(Test)', '对方回应简短但仍有礼貌时：先同步他的能量水平（不要过于热情），给予信息而非追问，浮动试探话题，测试他是否有互动意愿。', '适用场景：和谨慎、内敛、不太熟悉的人交流。', '社交-性格应对', 134),
('model', 'COLD冷淡者应对', '随意(Casual)→给予选项(Offer)→低投入(Low effort)→不施压(Don''t push)', '对方回复极简、无明显互动意愿时：保持随意，给予选项而非追问，降低自己的投入，不施压。有时候放手比死缠更有效。', '适用场景：对方明显不想深聊、关系尚未建立时。', '社交-性格应对', 135),
('model', 'EMPTY极冷应对', '回应情绪(Echo)→镜像状态(Mirror)→停顿(Pause)→微小扩展(Tiny expand)→让出话轮(Yield)', '对方只回"嗯""哦""累"时：先回应他的情绪（"听起来很累"），镜像他的状态，停顿给空间，做一个极小的扩展，然后让出话轮。不要强迫对话。', '适用场景：对方完全封闭但尚未明确拒绝时。', '社交-性格应对', 136),
('model', '应急应对模型', '现状→预判→应对，按需换口径/时间/地点/角色', '面对冒犯提问、敌对质疑或尴尬话题时：快速评估现状，预判对方下一步，选择应对策略。可以换口径（换个说法）、换时间（晚点再说）、换地点（私下聊）、换角色（让更合适的人回答）。', '适用场景：面对冒犯提问、敌对质疑、尴尬话题。', '社交-破冰闲聊', 137),

-- ========== 应变模型：补充 ==========
('model', '基线对比法', '先判断对方平时状态，再识别当前是否异常', '先建立对方的"正常基线"——平时的语气、提问方式、行为模式。然后对比当前表现，识别是否有异常。如果突然变热情或变冷淡，可能在试探你。', '适用场景：判断对方是否在试探、识破异常行为。', '应变-认知分析', 138),
('model', '声东击西', '立刻抛出更吸引注意力的话题转移焦点', '当对方追问你不想回答的问题时，立刻抛出一个更吸引注意力的话题。"对了，你知道吗……"——转移焦点，让对方跟着你的节奏走。', '适用场景：被追问不想回答的问题、需要转移注意力时。', '应变-沟通策略', 139),
('model', '柔道原则', '不正面对抗，借助对方力道反弹', '不和对方硬刚，而是借助对方的质疑变成支持你的理由。"你说得对，正是因为这个问题存在，所以我们更需要这个方案。"', '适用场景：被质疑时需要巧妙回应、不想正面对抗但要维护立场。', '应变-沟通策略', 140),
('model', '是的而且法则', '不否认不硬刚，顺着对方说然后叠加自己的叙事', '不要否认对方说的（那会变成对抗），而是先说"是的"，然后"而且"加上你的版本。"是的，我确实在看手机，而且我正在查你刚才提到的那个数据。"', '适用场景：被质疑、需要化解尴尬、不想陷入防守时。', '应变-沟通策略', 141),
('model', '话题封口法', '回答后主动收口避免被连续追问', '回答完一个问题后，主动加一句收口的话，避免被连续追问。"差不多就是这样，后面我再同步你""具体细节下次再聊"——给对话画句号。', '适用场景：不想被继续追问、需要控制对话节奏时。', '应变-沟通策略', 142),
('model', '选择性透明', '只给安全信息，让对方感觉你没有隐瞒', '不需要全盘托出。只给"安全信息"——真实的、不敏感的、不会被利用的信息。让对方感觉你在坦诚交流，但实际上你控制了信息边界。', '适用场景：不想完全隐瞒但也不能全说时。', '应变-沟通策略', 143),
('model', '切割责任法', '明确责任边界避免被整体归因', '当问题发生时，明确区分哪些是你负责的，哪些不是。不要让对方把整个问题归因到你身上。"这个部分是我在负责，但那个部分是另一个团队的接口。"', '适用场景：被甩锅、需要明确责任边界时。', '应变-危机公关', 144),
('model', '节奏重置法', '当对话混乱或失控时强行拉回结构', '对话混乱、跑题、情绪化时，主动拉回结构。"我们先对齐一个关键点再继续""让我先确认一下我们讨论的核心问题是什么"——重置节奏。', '适用场景：会议失控、讨论跑题、多人争论混乱时。', '应变-危机公关', 145),
('model', '信息不对称策略', '利用对方不知道你知道多少制造心理优势', '不主动确认对方掌握了什么信息，让对方先说。你知道的比对方多，就是你的优势。反之，如果你不确定对方知道多少，不要先暴露自己的底牌。', '适用场景：谈判、竞争、任何信息博弈场景。', '应变-心理博弈', 146),
('model', '沉默压迫', '短暂停顿不回应让对方主动补充信息', '有时候最好的回应是不回应。短暂停顿3-5秒，对方会因为不安而主动补充信息、让步或暴露真实意图。沉默是最便宜的谈判工具。', '适用场景：谈判、质问、需要让对方先表态时。', '应变-心理博弈', 147),
('model', '镜像反射', '重复对方关键词引导其继续说', '重复对方话中的关键词，引导他继续说下去。"你是说''不太对劲''？"——对方会自动解释更多，给你更多信息和思考时间。', '适用场景：需要更多信息、想让对方多说、争取思考时间时。', '应变-心理博弈', 148),
('model', '低预期管理', '提前降低对方预期后续更容易形成正向反馈', '先说"这个方案还不太成熟"或"我可能说得不太好"，对方预期降低后，你实际表现只要正常就会被加分。这是预期管理，不是自我贬低。', '适用场景：准备不充分、不确定结果、想给自己留余地时。', '应变-心理博弈', 149),
('model', '角色反转法', '主动切换到对方角色让自己变成发问者', '当你快被"抓住"时，不要继续防守，而是反客为主。"你是什么意思？你觉得我在撒谎吗？"——让追问者陷入为自己辩解的境地。', '适用场景：被持续追问、需要打破被动局面时。', '应变-心理博弈', 150),
('model', '自信溢出效应', '以不容置疑的语气说话让对方怀疑自己', '用坚定的语气和姿态说话，让对方开始怀疑自己的判断是否有误，而不是怀疑你。自信的人定义现实，犹豫的人被现实定义。', '适用场景：需要镇住场面、建立权威、不想被质疑时。', '应变-心理博弈', 151),
('model', '主动坦白小事', '主动承认无关痛痒的小缺点塑造诚实形象', '主动、自然地承认一个无关紧要的小缺点或小事（"我确实有点拖延"），塑造"诚实人"形象。这让你在其他事情上更容易被信任。', '适用场景：需要建立信任、塑造坦诚形象时。', '应变-心理博弈', 152),
('model', '制造更紧迫的事', '构造更紧急的事转移对方注意力', '被追问时，立刻构造一个"更紧急的事"让对方把注意力转移过去。手机突然响起、想起一个重要会议、需要立刻处理另一个问题——给自己一个体面的退出。', '适用场景：被持续追问、需要脱身时。', '应变-心理博弈', 153),
('model', '锚定叙事', '比对方更早给事件定性抢占叙事主动权', '谁先说谁定调。一旦你的叙事框架被接受，对方的质疑就成了"对你叙事的补充"而非推翻。先发制人定义事件性质，比事后解释有效10倍。', '适用场景：事件即将被讨论、需要主动控制叙事方向时。', '应变-心理博弈', 154),
('model', '压力回传法', '把证明的压力推回给对方', '当对方质疑你时，不要急于自证，而是把压力推回去。"你是什么意思？你觉得我在说谎吗？"——让追问者陷入为自己辩解的境地。', '适用场景：被无端质疑、需要打破被动防守局面时。', '应变-心理博弈', 155),
('model', '社会认同背书', '引入第三方证人强化自己的故事', '主动引入"第三方"来强化你的可信度。"你可以去问王总，我们当时在一起"——不管是否属实，先建立这个框架，让对方知道验证成本很高。', '适用场景：需要增强可信度、让对方难以质疑时。', '应变-心理博弈', 156),
('model', '恐慌接种', '主动承认事情看起来奇怪再给出解释', '先承认"这件事看起来确实很奇怪，我理解你为什么这么想"，然后给出解释。这叫"接种"——先接受对方的怀疑，再瓦解它。比直接否认有效得多。', '适用场景：对方已经起疑、需要化解怀疑时。', '应变-心理博弈', 157),
('model', '信息分段释放', '不一次说完分批给信息边观察边调整', '不要一次性把所有信息都倒出来。分批释放，边说边观察对方反应，根据反馈调整后续信息的内容和深度。保持信息优势。', '适用场景：谈判、汇报、任何需要控制信息节奏的场景。', '应变-心理博弈', 158),
('model', '叙事替换', '当原叙事不利时直接切换解释框架', '当你的解释已经不被信任时，不要继续修补，直接切换到一个全新的解释框架。"其实换个角度看……"——新框架比修补旧框架更有效。', '适用场景：原解释已经失效、需要彻底换一个角度时。', '应变-心理博弈', 159),
('model', '预设立场', '在对话开始前限定对方理解角度', '在对话开始前，先限定讨论角度。"从资源限制来看……""从用户体验角度……"——这会引导对方在你设定的框架内思考。', '适用场景：会议开场、提案引导、任何需要控制讨论方向的场景。', '应变-心理博弈', 160),
('model', '退出机制', '提前设计结束方式避免被持续深挖', '进入对话前就想好怎么结束。设定时间限制、准备体面的退出理由、预设"改天再聊"的出口。不要让自己陷入无路可退的对话。', '适用场景：高风险对话、不想被持续追问、需要保护自己的场景。', '应变-心理博弈', 161)
ON DUPLICATE KEY UPDATE `name` = VALUES(`name`), `summary` = VALUES(`summary`);
-- +goose StatementEnd

-- +goose StatementBegin
INSERT INTO `model_scenario` (`type`, `name`, `summary`, `description`, `detail`, `category`, `sort_order`) VALUES

-- ========== 场景：职场 ==========
('scenario', '同事抢功', '同事在会议上把你的方案据为己有', '你在团队会议上提出了一个方案，但同事在向上汇报时把功劳归于自己。领导以为是他做的，你在旁边有口难言。这种情况已经不是第一次了。', '应对策略：1）会后私下找对方谈，用DESC模型设立边界；2）以后重要方案通过邮件留痕，抄送相关人；3）在会议上主动承担汇报角色；4）如果持续发生，用SBI模型向领导反馈事实。', '职场', 1),
('scenario', '年终述职', '领导要求你用5分钟说清一年的价值', '年终述职时，领导对你全年工作提出质疑：数据来源不清楚、失败案例被追问、KPI框架复杂让你难以回答。你需要在有限时间内展示自己的价值。', '应对策略：1）用STAR模型结构化讲述关键项目；2）用SCQA模型准备核心方案；3）事前验尸，提前准备可能被追问的问题；4）用PREP模型回答每个质疑。', '职场', 2),
('scenario', '领导当众批评', '领导在会议上当众批评你的工作', '领导在全体会议上直接指出你的问题，语气严厉，让你在同事面前很没面子。你需要当场回应，既不能硬刚也不能完全示弱。', '应对策略：1）用扑克脸原则控制情绪；2）先承认事实；3）用AER模型提出补救方案；4）会后私下沟通，用NVC表达你的感受。', '职场', 3),
('scenario', '临时顶替发言', '突然被要求代替领导或同事发言', '领导临时有事，让你代替他在重要会议上发言。你没有准备，台下坐着比你级别高的人。', '应对策略：1）用三秒原则，先开口不要冷场；2）用即兴发言公式（赞同+细节+谦虚）；3）用PREP结构化表达核心观点；4）如果实在不确定，用递延回应法争取时间。', '职场', 4),
('scenario', '客户突然发飙', '客户在沟通中突然情绪爆发', '客户因为产品问题或交付延迟，在电话或当面沟通中突然发飙，语气激烈，甚至带有攻击性。你需要快速平息对方情绪。', '应对策略：1）用STOP模型先让自己冷静；2）用3C原则（关注→承诺→控制）；3）先倾听不打断，用积极倾听3F理解他的真实诉求；4）用AER模型提出补救方案。', '职场', 5),

-- ========== 场景：职场进阶 ==========
('scenario', '功劳被系统性压制', '长期做事但评价很低', '你持续做了很多核心工作，但绩效评估中总被忽略，晋升名单从不出现你的名字，领导觉得你"还不错但不突出"。', '应对策略：1）建立可量化成果日志（结果而非过程）；2）会议中主动"轻曝光"（让别人知道你在做什么）；3）绑定关键项目owner身份；4）周期性向上对齐价值认知。', '职场进阶', 6),
('scenario', '被边缘化分配任务', '重要项目总轮不到你', '团队中重要资源、项目、机会不断流向同一批人，你被安排做支持性或重复性工作。', '应对策略：1）识别决策链而非执行链；2）主动争取"关键节点任务"；3）建立可替代性降低但可见性提高；4）用一次成功项目打破标签。', '职场进阶', 7),
('scenario', '领导风格冲突', '你和领导工作方式完全不一致', '领导偏激进/保守/控制型，你偏理性/自主/结构化，导致频繁误解和返工。', '应对策略：1）识别领导决策偏好（安全/速度/控制）；2）用对方语言包装你的方案；3）减少解释增加结果；4）建立低冲突沟通节奏。', '职场进阶', 8),
('scenario', '加班与工作量不对等', '你承担明显更多工作', '同级别中你承担明显更高工作量，但没有额外回报或认可。', '应对策略：1）量化工作负载；2）向上沟通资源失衡；3）设置边界避免无限扩展；4）绑定成果与资源申请。', '职场进阶', 9),

-- ========== 场景：组织政治 ==========
('scenario', '跨部门甩锅', '问题被推到你这边', '跨部门项目出问题，对方把责任归因到你执行不到位，但实际问题在对方接口或资源。', '应对策略：1）用时间线还原事实；2）用文档证据锁定边界；3）避免情绪对抗只谈流程；4）推动制度化接口定义。', '组织政治', 10),
('scenario', '被排除在决策之外', '重要讨论没人通知你', '你负责相关模块，但关键会议没有邀请你参与，导致后续执行被动。', '应对策略：1）反向锁定决策入口；2）主动要求"参与前置评审"；3）建立信息节点代理人；4）把自己变成"必须被依赖的人"。', '组织政治', 11),
('scenario', '隐性竞争关系', '同事表面合作但实际竞争晋升', '团队中有人表面合作，但在资源分配、汇报中暗中削弱你。', '应对策略：1）减少信息裸露；2）关键成果自己留痕；3）不在非必要场景暴露弱点；4）建立独立价值标签。', '组织政治', 12),
('scenario', '上级与上上级意见冲突', '两个层级领导要求相反', '直属领导和更高层领导对同一事项有冲突指令，你必须选择执行路径。', '应对策略：1）拆解冲突为时间/范围差异；2）优先确认最终责任人；3）用书面记录保护自己；4）避免个人站队。', '组织政治', 13),
('scenario', '被当作替罪羊预设', '出问题时你总是被优先怀疑', '组织里形成惯性：一旦有问题，你总是第一个被提及或质疑的人。', '应对策略：1）建立事前证据链；2）让流程可追溯；3）扩大参与者边界；4）减少单点责任暴露。', '组织政治', 14),
('scenario', '功劳被结构性吸收', '成果进入组织但不归你个人', '你的成果被团队或部门吸收，但个人贡献无法体现。', '应对策略：1）绑定署名机制；2）在汇报链中加入个人节点；3）控制关键交付展示权；4）强化外部可见性。', '组织政治', 15),

-- ========== 场景：人际关系 ==========
('scenario', '家庭矛盾', '过年回家面对亲戚的灵魂拷问', '过年回家，七大姑八大姨问工资多少、什么时候结婚、什么时候生孩子、为什么不考公务员。你不想回答但又不想撕破脸。', '应对策略：1）用模糊回应策略不给具体信息；2）用重构叙事改变话题方向；3）用EASE模型应对不太熟的亲戚；4）用拒绝模型（三明治结构）温和设立边界。', '人际关系', 16),
('scenario', '朋友借钱', '朋友开口借钱但你不想借', '关系还不错的朋友找你借钱，金额不小。你不想借但又怕伤感情。对方可能正在经历困难，但你也有自己的顾虑。', '应对策略：1）用拖延答复法争取思考时间；2）用三明治拒绝法（肯定关系→说明困难→提供其他帮助）；3）不要给模糊承诺，明确但温和地拒绝。', '人际关系', 17),
('scenario', '被当众比较', '被长辈拿来和别人比较', '家庭聚会上，亲戚当着你的面说"你看人家小王，年薪百万""还是你姐有本事"。你感到不舒服但不知道怎么回应。', '应对策略：1）不要硬刚或自证；2）用重构叙事化解（"每个人节奏不同"）；3）用保护被比较者的话术维护自己和被比较的人；4）用模糊回应策略带过。', '人际关系', 18),
('scenario', '伴侣冷战', '和伴侣吵架后进入冷战状态', '你和伴侣因为一件小事吵了起来，现在双方都不说话。你想修复关系但不知道怎么开口，怕又吵起来。', '应对策略：1）用LARA模型降级冲突；2）用NVC表达你的感受和需求；3）用REPAIR关系修复模型主动破冰；4）不要争论谁对谁错，先修复连接。', '人际关系', 19),
('scenario', '被频繁求助', '别人总来找你帮忙', '朋友或同事频繁找你帮忙，占用大量时间，但关系并未对等回馈。', '应对策略：1）设置响应延迟；2）区分可帮与不可帮；3）减少即时响应；4）建立边界表达。', '人际关系', 20),

-- ========== 场景：社交尴尬 ==========
('scenario', '当众出糗', '在公共场合出了洋相', '你在会议上口误、在餐厅摔了东西、认错了人热情打招呼。周围人都在看你，你恨不得找个地缝钻进去。', '应对策略：1）用扑克脸原则不要过度反应；2）用自嘲化解尴尬；3）用RELAX模型处理自己的情绪；4）大多数人的记忆力比你想象的短。', '社交尴尬', 21),
('scenario', '发错消息', '微信/邮件发错了对象', '你把吐槽领导的消息发到了工作群，把给朋友的私密对话发到了家庭群，或者把不该让某人看到的内容发给了对方。', '应对策略：1）能撤回立刻撤回；2）不能撤回用重构叙事；3）如果被追问，用最小信息原则不要过度解释；4）主动发一条正常消息覆盖。', '社交尴尬', 22),
('scenario', '说错话', '在重要场合说了不该说的话', '你在饭局上不小心说了某个敏感话题、在领导面前说了不该说的真话、在社交场合冒犯了某人。话说出口才意识到不对。', '应对策略：1）立刻用A.A.A.补救模型（承认→致歉→调整）；2）不要假装没说过，主动补救比被动等待好；3）用重构叙事改变话题方向；4）事后单独找对方沟通修复关系。', '社交尴尬', 23),
('scenario', '社交疲劳', '不想见人但不得不社交', '你并不想参与社交活动，但因为关系或责任不得不参与。', '应对策略：1）控制参与时长；2）降低参与深度；3）设定退出机制；4）优先关键关系。', '社交尴尬', 24),

-- ========== 场景：突发状况 ==========
('scenario', '被撞见秘密', '被发现了不想让人知道的事', '被伴侣发现藏了私房钱、被同事发现你在摸鱼、被领导发现你在面试其他公司。对方正在等你解释。', '应对策略：1）用扑克脸原则控制慌张信号；2）用重构叙事提供合理解读；3）用最小信息原则不过度解释；4）用先发制人主动掌握叙事。', '突发状况', 25),
('scenario', '迟到解释', '迟到后需要向领导/客户解释', '你迟到了，领导或客户正在等你。你需要给出一个合理的解释，同时不能显得不负责任。', '应对策略：1）用AER模型（承认→解释→补救）；2）不要编造过于复杂的借口；3）用最小信息原则简短说明；4）重点放在补救措施上而不是原因上。', '突发状况', 26),
('scenario', '钱包被偷', '在公共场所发现钱包/手机被偷', '你在地铁、商场或餐厅发现钱包或手机被偷了。你身上没有现金，需要处理报警、挂失、借钱回家等一系列问题。', '应对策略：1）用STOP模型先冷静；2）用风险优先级排序（先挂失银行卡，再报警，再联系家人）；3）用求助模型向周围人寻求帮助；4）事后复盘提高防范意识。', '突发状况', 27),
('scenario', '突发重大失误', '造成明显损失', '你的操作或判断导致明显业务损失，需要面对追责。', '应对策略：1）立即止损；2）快速透明汇报；3）提供补救路径；4）降低不可控扩散。', '突发状况', 28),

-- ========== 场景：压力场景 ==========
('scenario', '被质疑诚信', '有人质疑你说的话是否真实', '在讨论中，对方直接或间接暗示你在说谎、夸大或隐瞒信息。你需要回应这个质疑，同时不能表现得心虚。', '应对策略：1）用扑克脸原则不要慌；2）用压力回传法；3）用可信细节注入增强说服力；4）不要过度解释，过度解释反而显得心虚。', '压力场景', 29),
('scenario', '多人围攻', '被多人同时质疑或追问', '在会议或讨论中，多个人同时对你的方案提出质疑。你需要在压力下保持冷静并逐一回应。', '应对策略：1）用节奏重置法拉回结构；2）用OODA循环快速分析每个人的意图；3）用PREP结构化回应每个质疑；4）不要被情绪带跑，专注于事实。', '压力场景', 30),
('scenario', '重要谈判', '涉及利益分配的关键谈判', '薪资谈判、商业合作、合同条款——涉及双方利益分配的关键对话。对方可能比你更有经验或更有筹码。', '应对策略：1）用逆向归纳法从终点倒推准备；2）用BATNA分析你的底线；3）用信号模型判断对方真实意图；4）用混合策略避免被完全预测。', '压力场景', 31),
('scenario', '公开被否定核心能力', '当众被说不行', '在公开场合被直接否定能力或价值，甚至被领导点名质疑。', '应对策略：1）控制情绪不反击；2）拆解为具体问题；3）会后重建叙事；4）用结果快速反证。', '压力场景', 32),
('scenario', '被迫站队', '被要求在两个对立方中选边', '团队或人际冲突中被迫表态支持一方，否则被双方同时质疑。', '应对策略：1）拆分议题而非站队；2）强调共同目标；3）保持部分中立空间；4）避免情绪绑定任何一方。', '压力场景', 33),

-- ========== 场景：冲突升级 ==========
('scenario', '对方情绪升级失控', '沟通中对方开始人身攻击', '在争论中，对方从事实争论升级为情绪攻击或人格否定。', '应对策略：1）立即降级话题到事实层；2）停止回应情绪攻击；3）用边界话术终止无效沟通；4）必要时中断对话。', '冲突控制', 34),
('scenario', '误解不断放大', '解释越多对方越不信', '你试图解释一个误会，但对方不断曲解你的解释，冲突越来越大。', '应对策略：1）停止重复解释；2）转为结果导向表达；3）承认感受不承认错误；4）用第三方事实重建信任。', '冲突控制', 35),
('scenario', '信任体系崩塌', '关键关系彻底破裂', '与核心合作方或领导信任完全破裂，短期无法修复。', '应对策略：1）停止解释；2）转为事实交付；3）建立最小合作协议；4）准备关系替代结构。', '冲突控制', 36),

-- ========== 场景：沟通操控 ==========
('scenario', '对方使用情绪绑架', '用关系或情绪压你让步', '对方用"你是不是不在乎我们关系""你这样太冷血"等方式迫使你让步。', '应对策略：1）区分情绪与事实；2）不进入情绪框架；3）重复边界；4）回到规则与结果。', '心理博弈', 37),
('scenario', '对方反复否认事实', '明明发生过但对方否认', '对方在争论中否认已经发生的事实，使讨论陷入无解循环。', '应对策略：1）停止口头争论；2）引入外部记录；3）用时间线固定事实；4）降低沟通频率。', '心理博弈', 38),
('scenario', '对方制造模糊责任', '故意不说清责任边界', '对方在合作中刻意模糊职责，导致问题发生时无法追责。', '应对策略：1）书面化责任边界；2）强制节点确认；3）用会议纪要锁定；4）拒绝模糊执行。', '心理博弈', 39),

-- ========== 场景：晋升与评价 ==========
('scenario', '晋升被卡住但无明确理由', '绩效正常但晋升迟迟不到', '你连续几个周期表现正常甚至不错，但始终没有进入晋升名单，领导也不给明确反馈。', '应对策略：1）强制要求晋升标准具体化；2）对标已晋升人员差距；3）制造"不可忽视的关键成果"；4）设定离开选项作为压力信号。', '晋升博弈', 40),
('scenario', '评价标准频繁变化', '今年标准和去年完全不同', '绩效评估规则不断变化，导致你无法稳定对齐目标，结果不透明。', '应对策略：1）锁定评价决策人而非制度；2）提前确认隐性标准；3）保守+关键突破组合策略；4）减少对规则依赖，提高对人依赖理解。', '晋升博弈', 41),
('scenario', '被标签化评价', '被固定印象限制发展', '你被贴上"执行型""不够主动""不够激进"等标签，导致后续评价持续偏见化。', '应对策略：1）用反标签项目打破认知；2）主动输出跨类型能力；3）制造认知冲击点；4）更换评价者视角。', '晋升博弈', 42),
('scenario', '薪资涨幅不透明', '涨薪远低于预期但没有解释', '绩效不错但薪资涨幅明显低于团队平均水平，公司不给明确解释。', '应对策略：1）收集市场对标数据；2）明确提出增长区间；3）绑定关键贡献点；4）准备替代方案（BATNA）。', '晋升博弈', 43),

-- ========== 场景：信息与资源 ==========
('scenario', '关键消息被延迟传达', '你总是最后一个知道', '重要信息、变更或决策总是晚一步才传到你，影响执行节奏。', '应对策略：1）建立信息源网络；2）绑定关键节点人；3）主动参与决策前讨论；4）减少单点依赖信息链。', '信息控制', 44),
('scenario', '信息被选择性传递', '别人只告诉你部分信息', '你获取的信息是经过过滤或裁剪的，导致判断失真。', '应对策略：1）多渠道交叉验证；2）直接接触源头；3）对信息做假设检验；4）识别信息操控动机。', '信息控制', 45),
('scenario', '你被当作执行终点', '只让你做具体执行不参与决策', '你只被分配执行任务，不参与设计和方向讨论。', '应对策略：1）向上渗透设计环节；2）在执行中反推决策逻辑；3）用执行结果反向影响设计；4）争取部分决策权。', '信息控制', 46),
('scenario', '资源争夺失败', '项目资源被别人抢走', '你争取的预算、人力或项目被分配给其他团队或同事。', '应对策略：1）提前锁定资源承诺；2）增加决策参与权；3）建立优先级可视化；4）减少被替代性。', '资源分配', 47),

